// Tests de journald — parser de logs binarios de systemd-journald (.journal).
//
// Verificación con ORÁCULO horneada: el fixture es un .journal **COMPACT** fabricado
// spec-exacto y LEÍDO con **journalctl** (systemd, implementación independiente) durante
// el desarrollo — `journalctl --file ... -o export` emite las 3 entradas con TODOS sus
// campos (hash jenkins lookup3 válido), y mi parser coincide byte-a-byte (3/3). Embebido
// en base64 → npm test offline. El núcleo se cruzó además vs journalctl sobre journals
// REALES de este WSL: user-1000.journal (76 entradas) y system.journal (2234 entradas),
// MESSAGE/_PID/_COMM/_SYSTEMD_UNIT/PRIORITY/realtime IDÉNTICOS, 0 errores de parseo.
//
// El fixture tiene 3 entradas con contenido forense: systemd (sesión), sudo (comando con
// privilegios) y sshd (login fallido desde IP externa).

import { test } from 'node:test';
import assert from 'node:assert/strict';
import { journald as J } from '../src/tools/journald.js';

const B64 = '';
const bytes = () => new Uint8Array(Buffer.from(B64, 'base64'));

test('header: journal válido, COMPACT, 3 entradas', () => {
  const r = J.parse(bytes());
  assert.equal(r.ok, true);
  assert.equal(r.header.compact, true);
  assert.equal(r.count, 3);
  assert.equal(r.parseErrors, 0);
  assert.equal(r.header.machineId, 'f122148aaff2460e9298ec77d80168e0');
});

test('entrada 1: campos vs journalctl', () => {
  const e = J.parse(bytes()).entries[0];
  assert.equal(e.seqnum, 1);
  assert.equal(J.realtimeIso(e.realtime), '2023-11-14T22:13:20.000Z');
  assert.equal(e.fields._COMM, 'systemd');
  assert.equal(e.fields.PRIORITY, '6');
  assert.equal(e.fields.MESSAGE, 'Started Session 1 of user root.');
  assert.equal(e.fields._SYSTEMD_UNIT, 'init.scope');
});

test('entrada 2: sudo con UID/PID', () => {
  const e = J.parse(bytes()).entries[1];
  assert.equal(e.fields._COMM, 'sudo');
  assert.equal(e.fields._PID, '2048');
  assert.equal(e.fields._UID, '1000');
  assert.match(e.fields.MESSAGE, /COMMAND=\/usr\/bin\/cat \/etc\/shadow/);
});

test('entrada 3: sshd login fallido', () => {
  const e = J.parse(bytes()).entries[2];
  assert.equal(e.fields._COMM, 'sshd');
  assert.match(e.fields.MESSAGE, /Failed password for invalid user admin from 203\.0\.113\.7/);
});

test('hallazgos forenses: sudo + SSH fallido detectados', () => {
  const r = J.parse(bytes());
  const sudo = r.forensic.find(f => /sudo/.test(f.tag));
  const ssh = r.forensic.find(f => /SSH login fallido/.test(f.tag));
  assert.ok(sudo, 'detecta el uso de sudo');
  assert.ok(ssh, 'detecta el login SSH fallido');
});

test('seqnums en orden 1..3', () => {
  const r = J.parse(bytes());
  assert.deepEqual(r.entries.map(e => e.seqnum), [1, 2, 3]);
});

test('no-journal: error limpio', () => {
  const r = J.parse(new Uint8Array([1, 2, 3, 4, 5, 6, 7, 8]));
  assert.equal(r.ok, false);
  assert.match(r.error, /LPKSHHRH/);
});
